class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def reverseKGroup(self, head: ListNode, k: int) -> ListNode:
        current = head
        count = 0

        while current and count < k:
            current = current.next
            count += 1

        if count == k:
            new_head_of_next_group = self.reverseKGroup(current, k)

            prev = None
            curr = head
            for _ in range(k):
                next_node = curr.next
                curr.next = prev
                prev = curr
                curr = next_node

            head.next = new_head_of_next_group
            return prev
        else:
            return head
